dict.string:
function style(text, code) {
  return "\033[" + code + "m" + text + "\033[0m";
}

function underline(text) {
  return style(text, 4);
}

function bold(text) {
  return style(text, 1);
}

function red(text) {
  return style(text, 31);
}

function green(text) {
  return style(text, 32);
}

function testArrays(actualArray, expectedArray, message) {
  if (areEqual(actualArray, expectedArray)) {
    return green("󰗡 ") + message ; 
  }
  return red(" ") + message + green("\n\texpected:" + expectedArray) + red("\n\tatcutal: " + actualArray);
}

function test(actual, expected, message) {
  if (actual === expected) {
    return green("󰗡 ") + message ; 
  }
  return red(" ") + message + green("\n\texpected: " + expected) + red("\n\tatcutal: " + actual);
}

function showTitle(title)  {
  console.log(bold(underline(title)));
}

function printReport(actual, expected, message) {
  console.log(test(actual, expected, message));
}

function printReportArrays(actualArray, expectedArray, message) {
  console.log(testArrays(actualArray, expectedArray, message));
}
